namespace sv_08c870f5cd5e460b91a4ef40078001ad.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = [];

    public IReadOnlyList<CartItem> Items => _items;

    public int TotalCount => _items.Sum(i => i.Quantity);

    public decimal TotalPrice => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(int id, string name, decimal price)
    {
        var existing = _items.Find(i => i.Id == id);
        if (existing is not null)
        {
            existing.Quantity++;
        }
        else
        {
            _items.Add(new CartItem { Id = id, Name = name, Price = price, Quantity = 1 });
        }
        NotifyStateChanged();
    }

    public void Remove(int id)
    {
        _items.RemoveAll(i => i.Id == id);
        NotifyStateChanged();
    }

    public void Clear()
    {
        _items.Clear();
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

@using sv_08c870f5cd5e460b91a4ef40078001ad.Services
@inject CartState Cart
@implements IDisposable
@rendermode InteractiveServer

<a href="cart" class="cart-badge-link">
    🛒
    @if (Cart.TotalCount > 0)
    {
        <span class="cart-badge">@Cart.TotalCount</span>
    }
</a>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

.cart-badge-link {
    color: white;
    text-decoration: none;
    position: relative;
    font-size: 1.3rem;
    display: inline-flex;
    align-items: center;
    padding: 0.25rem 0.5rem;
}

.cart-badge-link:hover {
    color: #ddd;
}

.cart-badge {
    position: absolute;
    top: -4px;
    right: -6px;
    background-color: #e74c3c;
    color: white;
    border-radius: 50%;
    font-size: 0.7rem;
    font-weight: bold;
    min-width: 1.2rem;
    height: 1.2rem;
    display: flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
}

@page "/products"
@using sv_08c870f5cd5e460b91a4ef40078001ad.Services
@inject CartState Cart
@rendermode InteractiveServer

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mt-2">
    @foreach (var product in products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, string Description, decimal Price);

    private readonly Product[] products =
    [
        new(1, "Wireless Headphones", "Noise-cancelling over-ear headphones", 79.99m),
        new(2, "Mechanical Keyboard", "RGB backlit with Cherry MX switches", 129.99m),
        new(3, "USB-C Hub", "7-in-1 multiport adapter", 34.99m),
        new(4, "Laptop Stand", "Adjustable aluminum stand", 49.99m),
        new(5, "Webcam HD", "1080p with built-in microphone", 59.99m),
        new(6, "Mouse Pad XL", "Extended desk mat with stitched edges", 19.99m),
    ];

    private void AddToCart(Product product)
    {
        Cart.Add(product.Id, product.Name, product.Price);
    }
}

@page "/cart"
@using sv_08c870f5cd5e460b91a4ef40078001ad.Services
@inject CartState Cart
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (Cart.Items.Count == 0)
{
    <p class="text-muted mt-3">Your cart is empty. <a href="products">Browse products</a></p>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-sm btn-danger" @onclick="() => Cart.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end fw-bold">Total:</td>
                <td class="fw-bold">@Cart.TotalPrice.ToString("C")</td>
                <td>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="Cart.Clear">
                        Clear All
                    </button>
                </td>
            </tr>
        </tfoot>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

